(() => {
    interface Person {
      name: string;
      age: number;
      createdAt: Date;
    }
    return {build: () => createValidate<Partial<Person>>(), buildErrors: () => noErrs(createGetValidationErrors<Partial<Person>>())};
  })()

c(z.custom((v) => {
    if (typeof v !== 'object' || v === null) return false;
    if (Object.prototype.toString.call(v) !== '[object Object]') return false;
    const obj = v as Record<string, unknown>;
    if ('name' in obj && obj.name !== undefined && typeof obj.name !== 'string') return false;
    if ('age' in obj && obj.age !== undefined && (typeof obj.age !== 'number' || !Number.isFinite(obj.age))) return false;
    if ('createdAt' in obj && obj.createdAt !== undefined) {
      if (!(obj.createdAt instanceof Date) || isNaN((obj.createdAt as Date).getTime())) return false;
    }
    return true;
  }))

c( // override: TypeBox accepts Date/Map/Set for all-optional objects — drop those from invalid
    Type.Partial(Type.Object({name: Type.String(), age: Type.Number(), createdAt: Type.Date()})),
    {
      valid: [{}, {name: 'John'}, {createdAt: new Date()}, {name: 'John', age: 30, createdAt: new Date()}],
      invalid: [[], {name: 42}, {createdAt: 'not date'}, null, undefined, {createdAt: new Date('invalid')}, {age: NaN}],
    },
  )
